/*
 * water_quality_monitor.ino — Portable Water Quality Monitor
 *
 * Elements:
 *   1. pH Probe BNC Module    — A0; 2-point cal from EEPROM
 *   2. Turbidity Sensor       — A1; polynomial NTU curve
 *   3. SSD1306 OLED           — live 3-param display at 1 Hz
 *   4. MicroSD Logger         — auto-save every 60 s
 *   5. Rotary Encoder         — manual save + calibration menu
 *   6. Arduino Nano 5 V       — orchestrator
 */

#include <Wire.h>
#include <Adafruit_SSD1306.h>
#include <SPI.h>
#include <SD.h>
#include <EEPROM.h>

// --- Pins ---
#define PH_PIN    A0
#define TURB_PIN  A1
#define TDS_PIN   A2
#define SD_CS     10
#define ENC_CLK    2
#define ENC_DT     4
#define ENC_SW     3

// --- EEPROM offsets for pH calibration ---
#define EE_PH_MID   0    // float: mid-point voltage (pH 7 buffer)
#define EE_PH_SLP   4    // float: slope (mV per pH unit)

// --- Globals ---
Adafruit_SSD1306 oled(128, 64, &Wire, -1);

float ph_mid  = 2.50f;   // default: 2.5 V = pH 7
float ph_slope = 0.18f;  // default: 0.18 V per pH unit

volatile int  enc_delta = 0;
volatile bool enc_press = false;

void ICACHE_RAM_ATTR on_clk() { enc_delta += digitalRead(ENC_DT) ? -1 : 1; }
void ICACHE_RAM_ATTR on_sw()  { enc_press  = true; }

float read_ph() {
  long sum = 0;
  for (int i = 0; i < 32; i++) { sum += analogRead(PH_PIN); delay(5); }
  float v = sum / 32.0f * 5.0f / 1023.0f;
  return 7.0f + (ph_mid - v) / ph_slope;
}

float read_ntu() {
  long sum = 0;
  for (int i = 0; i < 16; i++) { sum += analogRead(TURB_PIN); delay(3); }
  float v = sum / 16.0f * 5.0f / 1023.0f;
  float ntu = -1120.4f * v * v + 5742.3f * v - 4353.8f;
  return constrain(ntu, 0.0f, 3000.0f);
}

float read_tds() {
  long sum = 0;
  for (int i = 0; i < 16; i++) { sum += analogRead(TDS_PIN); delay(3); }
  float v = sum / 16.0f * 5.0f / 1023.0f;
  // TDS probe: 133.42 × v³ − 255.86 × v² + 857.39 × v (DFRobot SEN0244 formula)
  return 133.42f*v*v*v - 255.86f*v*v + 857.39f*v;
}

void save_to_sd(float ph, float ntu, float tds, uint32_t seq) {
  if (!SD.begin(SD_CS)) return;
  File f = SD.open("WQLOG.CSV", FILE_WRITE);
  if (f) {
    f.printf("%lu,%lu,%.2f,%.0f,%.0f\n", seq, millis()/1000, ph, ntu, tds);
    f.close();
  }
  SD.end();
}

void draw_oled(float ph, float ntu, float tds, bool saved) {
  oled.clearDisplay();
  oled.setTextSize(1); oled.setTextColor(SSD1306_WHITE);
  oled.setCursor(0,  0); oled.printf("pH:  %.2f %s", ph,  saved ? "[S]" : "   ");
  oled.setCursor(0, 20); oled.printf("NTU: %.0f", ntu);
  oled.setCursor(0, 36); oled.printf("TDS: %.0f ppm", tds);
  oled.display();
}

void setup() {
  Serial.begin(115200);
  Wire.begin();
  SPI.begin();

  oled.begin(SSD1306_SWITCHCAPVCC, 0x3C);
  oled.clearDisplay(); oled.display();

  EEPROM.get(EE_PH_MID,  ph_mid);
  EEPROM.get(EE_PH_SLP,  ph_slope);
  if (isnan(ph_mid) || isnan(ph_slope)) { ph_mid = 2.50f; ph_slope = 0.18f; }

  pinMode(ENC_CLK, INPUT_PULLUP);
  pinMode(ENC_DT,  INPUT_PULLUP);
  pinMode(ENC_SW,  INPUT_PULLUP);
  attachInterrupt(digitalPinToInterrupt(ENC_CLK), on_clk, FALLING);
  attachInterrupt(digitalPinToInterrupt(ENC_SW),  on_sw,  FALLING);

  Serial.println(F("Water quality monitor ready."));
}

void loop() {
  static unsigned long last_read  = 0;
  static unsigned long last_save  = 0;
  static uint32_t seq             = 0;
  static bool saved_flash         = false;

  unsigned long now = millis();

  noInterrupts(); int d = enc_delta; enc_delta = 0; bool p = enc_press; enc_press = false; interrupts();

  // --- 1. Read sensors ---
  float ph  = read_ph();
  float ntu = read_ntu();
  float tds = read_tds();

  // --- 2. Manual save on press ---
  if (p) { save_to_sd(ph, ntu, tds, seq++); saved_flash = true; last_save = now; }

  // --- 3. Auto-save every 60 s ---
  if (now - last_save >= 60000UL) {
    save_to_sd(ph, ntu, tds, seq++);
    saved_flash = true; last_save = now;
  } else {
    if (now - last_save > 500UL) saved_flash = false;
  }

  // --- 4. OLED update at 1 Hz ---
  if (now - last_read >= 1000UL) {
    last_read = now;
    draw_oled(ph, ntu, tds, saved_flash);
    Serial.printf("pH=%.2f NTU=%.0f TDS=%.0f\n", ph, ntu, tds);
  }
}
